
"use client";
import { useState, useEffect } from "react";
import { Filter, Check, X } from 'lucide-react';
import { getLabRequestsAction, updateLabRequestAction, getUsersAction, getSubjectsAction, getLabsAction } from "@/app/actions/dbActions";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { LabRequest, User, Subject, Lab } from "@/utils/storage";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import { toast } from "sonner";

export default function AllRequests() {
    const [requests, setRequests] = useState<LabRequest[]>([]);
    const [users, setUsers] = useState<User[]>([]);
    const [subjects, setSubjects] = useState<Subject[]>([]);
    const [labs, setLabs] = useState<Lab[]>([]);
    const [filter, setFilter] = useState('all');
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetchData();
    }, []);

    const fetchData = async () => {
        setLoading(true);
        try {
            const [reqs, usrs, subs, lbs] = await Promise.all([
                getLabRequestsAction(),
                getUsersAction(),
                getSubjectsAction(),
                getLabsAction(),
            ]);
            setRequests(reqs.sort((a, b) => new Date(b.startTime).getTime() - new Date(a.startTime).getTime()));
            setUsers(usrs);
            setSubjects(subs);
            setLabs(lbs);
        } catch (e) {
            toast.error("Failed to load data.");
        } finally {
            setLoading(false);
        }
    };

    const handleUpdateRequest = async (id: string, status: 'approved' | 'declined') => {
        try {
            await updateLabRequestAction(id, { status });
            toast.success(`Request has been ${status}.`);
            fetchData(); // Refresh data
        } catch {
            toast.error("Failed to update request.");
        }
    };

    const filteredRequests = requests.filter(r => filter === 'all' || r.status === filter);
    
    const getName = (id: string, type: 'user' | 'subject' | 'lab') => {
        switch(type) {
            case 'user': return users.find(u => u.id === id)?.name || id;
            case 'subject': return subjects.find(s => s.id === id)?.name || id;
            case 'lab': return labs.find(l => l.id === id)?.name || id;
            default: return id;
        }
    }

    return (
        <div>
            <div className="mb-8">
                <h1 className="text-3xl font-bold text-gray-800">Request Management</h1>
                <p className="text-muted-foreground">Track all student requests for LAB/room bookings.</p>
            </div>

            <div className="flex items-center gap-2 mb-6">
                <Filter className="h-5 w-5 text-gray-500" />
                <Button variant={filter === 'all' ? 'default' : 'outline'} onClick={() => setFilter('all')} style={filter === 'all' ? { backgroundColor: '#E30613', color: 'white' } : {}}>All</Button>
                <Button variant={filter === 'pending' ? 'default' : 'outline'} onClick={() => setFilter('pending')} style={filter === 'pending' ? { backgroundColor: '#E30613', color: 'white' } : {}}>Pending</Button>
                <Button variant={filter === 'approved' ? 'default' : 'outline'} onClick={() => setFilter('approved')} style={filter === 'approved' ? { backgroundColor: '#E30613', color: 'white' } : {}}>Approved</Button>
                <Button variant={filter === 'declined' ? 'default' : 'outline'} onClick={() => setFilter('declined')} style={filter === 'declined' ? { backgroundColor: '#E30613', color: 'white' } : {}}>Declined</Button>
            </div>

            <Card>
                <CardContent className="pt-6">
                   <Table>
                       <TableHeader>
                           <TableRow>
                               <TableHead>Student</TableHead>
                               <TableHead>Lab</TableHead>
                               <TableHead>PC#</TableHead>
                               <TableHead>Time</TableHead>
                               <TableHead>Status</TableHead>
                               <TableHead className="text-right">Actions</TableHead>
                           </TableRow>
                       </TableHeader>
                       <TableBody>
                           {loading && <TableRow><TableCell colSpan={6} className="text-center">Loading requests...</TableCell></TableRow>}
                           {!loading && filteredRequests.length === 0 && (
                               <TableRow><TableCell colSpan={6} className="text-center text-muted-foreground py-10">No requests found for this filter.</TableCell></TableRow>
                           )}
                           {!loading && filteredRequests.map(req => (
                               <TableRow key={req.id}>
                                   <TableCell>
                                       <div className="font-medium">{getName(req.studentId, 'user')}</div>
                                       <div className="text-sm text-muted-foreground">{getName(req.subjectId, 'subject')}</div>
                                   </TableCell>
                                   <TableCell>{getName(req.labId, 'lab')}</TableCell>
                                   <TableCell>{req.pcId?.split('-').pop()}</TableCell>
                                   <TableCell>
                                        {new Date(req.startTime).toLocaleTimeString()} - {new Date(req.endTime).toLocaleTimeString()}
                                        <div className="text-xs text-muted-foreground">{new Date(req.startTime).toLocaleDateString()}</div>
                                   </TableCell>
                                   <TableCell>
                                       <Badge variant={
                                           req.status === 'approved' ? 'secondary' :
                                           req.status === 'declined' ? 'destructive' :
                                           'outline'
                                       } className={
                                           req.status === 'approved' ? 'bg-green-100 text-green-800' :
                                           req.status === 'pending' ? 'bg-yellow-100 text-yellow-800' : ''
                                       }>{req.status}</Badge>
                                   </TableCell>
                                   <TableCell className="text-right">
                                       {req.status === 'pending' && (
                                           <div className="flex gap-2 justify-end">
                                               <Button size="icon" variant="outline" className="h-8 w-8 text-green-600 hover:bg-green-50" onClick={() => handleUpdateRequest(req.id, 'approved')}><Check className="h-4 w-4"/></Button>
                                               <Button size="icon" variant="outline" className="h-8 w-8 text-red-600 hover:bg-red-50" onClick={() => handleUpdateRequest(req.id, 'declined')}><X className="h-4 w-4"/></Button>
                                           </div>
                                       )}
                                   </TableCell>
                               </TableRow>
                           ))}
                       </TableBody>
                   </Table>
                </CardContent>
            </Card>

        </div>
    );
}
