
"use client";
import { useState, useEffect } from "react";
import { UserPlus, Mail, Shield, MoreVertical, Trash2 } from "lucide-react";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Badge } from "@/components/ui/badge";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { User } from "@/utils/storage";
import { getUsersAction, addUserAction, deleteUserAction } from "@/app/actions/dbActions";
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
    DialogTrigger,
    DialogFooter,
    DialogClose
} from "@/components/ui/dialog";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { toast } from 'sonner';

export default function ManageUsers() {
    const [users, setUsers] = useState<User[]>([]);
    const [loading, setLoading] = useState(true);
    const [isAddUserOpen, setAddUserOpen] = useState(false);
    const [isSaving, setIsSaving] = useState(false);
    const [newUser, setNewUser] = useState({ name: '', id: '', email: '', password: '', role: 'student' as User['role'] });
    const [userToDelete, setUserToDelete] = useState<User | null>(null);

    useEffect(() => {
        fetchUsers();
    }, []);

    const fetchUsers = async () => {
        setLoading(true);
        try {
            const userList = await getUsersAction();
            setUsers(userList);
        } finally {
            setLoading(false);
        }
    };

    const handleAddUser = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsSaving(true);
        try {
            await addUserAction({ ...newUser, profilePic: '' });
            toast.success("User added successfully!");
            setAddUserOpen(false);
            fetchUsers();
            setNewUser({ name: '', id: '', email: '', password: '', role: 'student' });
        } catch (err) {
            toast.error("Failed to add user.");
        } finally {
            setIsSaving(false);
        }
    };

    const handleDeleteUser = async () => {
        if (!userToDelete) return;
        try {
            await deleteUserAction(userToDelete.id);
            toast.success("User deleted successfully.");
            fetchUsers();
        } catch {
            toast.error("Failed to delete user.");
        } finally {
            setUserToDelete(null);
        }
    }

  return (
    <div>
        <div className="flex justify-between items-center mb-8">
            <div>
                <h1 className="text-3xl font-bold text-gray-800">User Management</h1>
                <p className="text-muted-foreground">Manage staff and student accounts.</p>
            </div>
            <Dialog open={isAddUserOpen} onOpenChange={setAddUserOpen}>
                <DialogTrigger asChild>
                    <Button className="gap-2 bg-primary hover:bg-primary/90 text-white">
                        <UserPlus className="h-4 w-4" /> Add User
                    </Button>
                </DialogTrigger>
                <DialogContent>
                    <DialogHeader>
                        <DialogTitle>Add New User</DialogTitle>
                    </DialogHeader>
                    <form onSubmit={handleAddUser} className="space-y-4">
                        <div className="space-y-2">
                            <Label htmlFor="id">USN/EMP</Label>
                            <Input id="id" value={newUser.id} onChange={e => setNewUser({...newUser, id: e.target.value})} required/>
                        </div>
                        <div className="space-y-2">
                            <Label htmlFor="name">Full Name</Label>
                            <Input id="name" value={newUser.name} onChange={e => setNewUser({...newUser, name: e.target.value})} required/>
                        </div>
                        <div className="space-y-2">
                            <Label htmlFor="email">Email</Label>
                            <Input id="email" type="email" value={newUser.email} onChange={e => setNewUser({...newUser, email: e.target.value})} required/>
                        </div>
                        <div className="space-y-2">
                            <Label htmlFor="password">Password</Label>
                            <Input id="password" type="password" value={newUser.password} onChange={e => setNewUser({...newUser, password: e.target.value})} required/>
                        </div>
                        <div className="space-y-2">
                            <Label htmlFor="role">Role</Label>
                            <Select value={newUser.role} onValueChange={(v: User['role']) => setNewUser({...newUser, role: v})}>
                                <SelectTrigger><SelectValue/></SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="student">Student</SelectItem>
                                    <SelectItem value="teacher">Teacher</SelectItem>
                                    <SelectItem value="admin">Admin</SelectItem>
                                </SelectContent>
                            </Select>
                        </div>
                        <DialogFooter>
                            <DialogClose asChild><Button type="button" variant="secondary">Cancel</Button></DialogClose>
                            <Button type="submit" disabled={isSaving}>{isSaving ? "Saving..." : "Save User"}</Button>
                        </DialogFooter>
                    </form>
                </DialogContent>
            </Dialog>
        </div>

        <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4">
            {loading && <p>Loading users...</p>}
            {!loading && users.map((user) => (
            <Card key={user.id} className="overflow-hidden hover:border-primary/50 transition-colors">
                <CardHeader className="pb-4">
                <div className="flex justify-between items-start">
                    <Avatar className="h-12 w-12 border-2 border-primary/10">
                    <AvatarImage src={user.profilePic} />
                    <AvatarFallback>{user.name.charAt(0)}</AvatarFallback>
                    </Avatar>
                    <DropdownMenu>
                    <DropdownMenuTrigger asChild>
                        <Button variant="ghost" size="icon" className="h-8 w-8">
                        <MoreVertical className="h-4 w-4" />
                        </Button>
                    </DropdownMenuTrigger>
                    <DropdownMenuContent align="end">
                        <DropdownMenuItem onClick={() => setUserToDelete(user)} className="text-destructive">
                            <Trash2 className="mr-2 h-4 w-4" />
                            Delete User
                        </DropdownMenuItem>
                    </DropdownMenuContent>
                    </DropdownMenu>
                </div>
                <CardTitle className="mt-4 text-lg">{user.name}</CardTitle>
                <CardDescription className="flex items-center gap-1">
                    <Mail className="h-3 w-3" /> {user.email}
                </CardDescription>
                </CardHeader>
                <CardContent>
                <div className="flex items-center justify-between">
                    <Badge variant={user.role === 'admin' ? 'default' : 'secondary'} className={`gap-1 capitalize ${
                        user.role === 'admin' ? 'bg-red-100 text-red-800' :
                        user.role === 'teacher' ? 'bg-blue-100 text-blue-800' :
                        'bg-green-100 text-green-800'
                    }`}>
                    <Shield className="h-3 w-3" /> {user.role}
                    </Badge>
                    <span className="text-xs text-muted-foreground">{user.id}</span>
                </div>
                </CardContent>
            </Card>
            ))}
        </div>
        <AlertDialog open={!!userToDelete} onOpenChange={() => setUserToDelete(null)}>
            <AlertDialogContent>
                <AlertDialogHeader>
                    <AlertDialogTitle>Are you absolutely sure?</AlertDialogTitle>
                    <AlertDialogDescription>
                        This action cannot be undone. This will permanently delete the user account for <span className="font-bold">{userToDelete?.name}</span>.
                    </AlertDialogDescription>
                </AlertDialogHeader>
                <AlertDialogFooter>
                    <AlertDialogCancel>Cancel</AlertDialogCancel>
                    <AlertDialogAction onClick={handleDeleteUser} className="bg-destructive hover:bg-destructive/90">Delete</AlertDialogAction>
                </AlertDialogFooter>
            </AlertDialogContent>
        </AlertDialog>
    </div>
  );
}
